() => {
  const sn = s => (s || '').split('/files/').pop().split('?')[0].slice(0, 60);
  const vw = innerWidth, vh = innerHeight, docW = document.documentElement.scrollWidth;
  const horizontalScroll = docW > vw + 1;
  let offenders = [];
  if (horizontalScroll) {
    document.querySelectorAll('body *').forEach(el => {
      if (offenders.length >= 8) return;
      const r = el.getBoundingClientRect();
      if (r.width > 0 && r.right > vw + 2 && getComputedStyle(el).position !== 'fixed') {
        const cls = (typeof el.className === 'string' && el.className.trim()) ? '.' + el.className.trim().split(/\s+/).slice(0, 2).join('.') : '';
        offenders.push(el.tagName.toLowerCase() + cls + ' r=' + Math.round(r.right));
      }
    });
  }
  const imgs = [...document.images].map(im => ({ s: sn(im.currentSrc || im.src), nat: [im.naturalWidth, im.naturalHeight], rend: [Math.round(im.width), Math.round(im.height)], broken: im.complete && im.naturalWidth === 0, alt: im.getAttribute('alt') }));
  const distorted = imgs.filter(i => { if (!i.nat[0] || !i.nat[1] || !i.rend[0] || !i.rend[1]) return false; const na = i.nat[0] / i.nat[1], ra = i.rend[0] / i.rend[1]; return Math.abs(na - ra) / na > 0.06; }).map(i => ({ n: i.s, nat: i.nat, rend: i.rend })).slice(0, 8);
  const upscaled = imgs.filter(i => i.nat[0] && i.rend[0] > i.nat[0] * 1.25).map(i => i.s).slice(0, 8);
  const hs = [...document.querySelectorAll('h1,h2,h3,h4,h5,h6')];
  const h1els = hs.filter(h => h.tagName === 'H1');
  const h1Empty = h1els.some(h => !(h.textContent || '').trim());
  let skipped = [], prev = 0;
  hs.forEach(h => { const l = +h.tagName[1]; if (prev && l > prev + 1) skipped.push(prev + '->' + l); prev = l; });
  let smallText = [], tinyTaps = [];
  if (vw <= 480) {
    [...document.querySelectorAll('p,li,a,span')].slice(0, 500).forEach(el => { const t = (el.textContent || '').trim(); if (t.length > 25) { const fs = parseFloat(getComputedStyle(el).fontSize); if (fs && fs < 14) smallText.push(Math.round(fs) + 'px:' + t.slice(0, 30)); } });
    smallText = [...new Set(smallText)].slice(0, 6);
    [...document.querySelectorAll('a,button,[role=button],input,select')].forEach(el => { const r = el.getBoundingClientRect(); if (r.width > 0 && r.height > 0 && (r.width < 44 || r.height < 44)) tinyTaps.push(Math.round(r.width) + 'x' + Math.round(r.height) + ' ' + ((el.textContent || el.getAttribute('aria-label') || el.tagName) || '').trim().slice(0, 22)); });
    tinyTaps = [...new Set(tinyTaps)].slice(0, 10);
  }
  const bt = document.body.innerText || '';
  const banned = ['effortless', 'elegant', 'curated', 'obsessed', 'must-have', 'put-together', 'daydream'];
  const bannedHits = banned.filter(w => new RegExp('\\b' + w.replace('-', '\\-') + '\\b', 'i').test(bt));
  if (/\bease\b/i.test(bt)) bannedHits.push('ease');
  return { url: location.pathname, title: document.title, vw, docW, horizontalScroll, offenders,
    imgCount: imgs.length, brokenImgs: imgs.filter(i => i.broken).map(i => i.s), zeroImgs: imgs.filter(i => (i.rend[0] === 0 || i.rend[1] === 0) && !i.broken).map(i => i.s),
    distorted, upscaled, altMissing: imgs.filter(i => i.alt === null || i.alt.trim() === '').length,
    altGeneric: imgs.filter(i => i.alt && /^(me ?\+ ?lia|image|photo|untitled|\S+\.(jpe?g|png|webp|gif))$/i.test(i.alt.trim())).map(i => i.alt).slice(0, 5),
    h1Count: h1els.length, h1Empty, headingCount: hs.length, skipped, smallText, tinyTaps,
    lorem: /lorem ipsum/i.test(bt), undef: /\bundefined\b/.test(bt), translationMissing: /translation missing/i.test(bt), liquidRaw: /(\{\{.*?\}\}|\{%.*?%\})/.test(bt),
    bannedHits, emDash: bt.includes('\u2014'), ship2day: /\b2\s*days?\b/i.test(bt), returns30: /\b30[\s-]*day/i.test(bt),
    springSale: (bt.match(/spring sale/gi) || []).length, soldOut: (bt.match(/sold ?out/gi) || []).length };
}

